//------------------------------------------------------------------------------
// main_tb.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
// Testbench template with basic clocking, reset and random stimulus signals

// use this define to make some things differently in simulation
`define SIMULATION yes

`timescale 1ns / 1ps

module main_tb();

logic clk200;
initial begin
  #0 clk200 = 1'b0;
  forever
    #2.5 clk200 = ~clk200;
end

// external device "asynchronous" clock
logic clk33a;
initial begin
  #0 clk33a = 1'b0;
  forever
    #7 clk33a = ~clk33a;
end

logic clk33;
//assign clk33 = clk33a;
always @(*) begin
  clk33 = #($urandom_range(0, 2000)*10ps) clk33a;
end

logic rst;
initial begin
  #0 rst = 1'b0;
  #10.2 rst = 1'b1;
  #5 rst = 1'b0;
  //#10000;
  forever begin
    #9985 rst = ~rst;
    #5 rst = ~rst;
  end
end

logic nrst;
assign nrst = ~rst;

logic rst_once;
initial begin
  #0 rst_once = 1'b0;
  #10.2 rst_once = 1'b1;
  #5 rst_once = 1'b0;
end

logic nrst_once;
assign nrst_once = ~rst_once;

logic [31:0] DerivedClocks;
clk_divider #(
  .WIDTH( 32 )
) cd1 (
  .clk( clk200 ),
  .nrst( nrst_once ),
  .ena( 1'b1 ),
  .out( DerivedClocks[31:0] )
);

logic [31:0] E_DerivedClocks;
edge_detect ed1[31:0] (
  .clk( {32{clk200}} ),
  .nrst( {32{nrst_once}} ),
  .in( DerivedClocks[31:0] ),
  .rising( E_DerivedClocks[31:0] ),
  .falling(  ),
  .both(  )
);

logic [31:0] RandomNumber1;
c_rand rng1 (
  .clk( clk200 ),
  .rst( 1'b0 ),
  .reseed( rst_once ),
  .seed_val( DerivedClocks[31:0] ^ (DerivedClocks[31:0] << 1) ),
  .out( RandomNumber1[15:0] )
);

c_rand rng2 (
  .clk( clk200 ),
  .rst( 1'b0 ),
  .reseed( rst_once ),
  .seed_val( DerivedClocks[31:0] ^ (DerivedClocks[31:0] << 2) ),
  .out( RandomNumber1[31:16] )
);

logic start;
initial begin
  #0 start = 1'b0;
  #100 start = 1'b1;
  #20 start = 1'b0;
end

// Module under test ==========================================================

logic [15:0] seq_cntr = '0;

logic [31:0] id = '0;
always_ff @(posedge clk200) begin
  if( ~nrst_once ) begin
    seq_cntr[15:0] <= '0;
    id[31:0] <= '0;
  end else begin
    // incrementing sequence counter
    if( seq_cntr[15:0]!= '1 ) begin
      seq_cntr[15:0] <= seq_cntr[15:0] + 1'b1;
    end

    if( seq_cntr[15:0]<300 ) begin
      id[31:0] <= '1;
      //id[31:0] <= {4{RandomNumber1[15:0]}};
    end else begin
      id[31:0] <= '0;
    end
  end
end


module_under_test #(
  .DEPTH( 255 ),
  .DATA_W( 32 )
) M (
  .clk( clk200 ),
  .nrst( nrst_once ),
  .ena( 1'b1 ),

  .id( id[31:0] ),
  .od(  )
);

// emulating external divice ==================================================
// that works asynchronously on clk33 clock

assign ADC1_SCLKOUT = clk33;

logic [15:0] test_data = 16'b1010_1100_1100_1111;
logic [7:0] adc1_seq_cntr = 0;
always_ff @(posedge clk33) begin
  if( adc1_seq_cntr[7:0]==0 && ~ADC1_nCONV ) begin
    ADC1_BUSY <= 1'b1;
    ADC1_SDOUT <= test_data[15];
    test_data[15:0] <= {test_data[14:0],1'b0};
    adc1_seq_cntr[7:0] <= 1;
  end

  if( adc1_seq_cntr[7:0]>0 && adc1_seq_cntr[7:0]<33 && ADC1_SCLKOUT) begin
    ADC1_SCLKOUT <= ~ADC1_SCLKOUT;
    // emulating adc1 data
    ADC1_SDOUT <= test_data[15];
    test_data[15:0] <= {test_data[14:0],1'b0};
    adc1_seq_cntr[7:0] <= adc1_seq_cntr[7:0] + 1'b1;
  end

  if( adc1_seq_cntr[7:0]>0 && adc1_seq_cntr[7:0]<33 && ~ADC1_SCLKOUT) begin
    ADC1_SCLKOUT <= ~ADC1_SCLKOUT;
    adc1_seq_cntr[7:0] <= adc1_seq_cntr[7:0] + 1'b1;
  end

  if( adc1_seq_cntr[7:0]==33 ) begin
    ADC1_BUSY <= 0;
    ADC1_SCLKOUT <= 0;
    ADC1_SDOUT <= 0;
    adc1_seq_cntr[7:0] <= 0;
  end
end

endmodule

//------------------------------------------------------------------------------
// Quartus test project template
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//------------------------------------------------------------------------------

// INFO ------------------------------------------------------------------------
// Quartus test project template, v4
// Compatible with DE10-Nano board
//
// - use this as a boilerplate project for fast prototyping
// - inputs and outputs are registered to allow valid timequest output
//   even if your custom logic/IPs have combinational outputs
// - SDC constraint file assigns clk to 500MHz to force fitter to synthesize
//   the fastest possible circuit
//

`timescale 1ns / 1ps

`include "define.svh"


`define WIDTH 32

module main(

  input FPGA_CLK1_50,
  input FPGA_CLK2_50,
  input FPGA_CLK3_50,

  // ADC
  input ADC_CONVST,
  input ADC_SCK,
  input ADC_SDI,
  input ADC_SDO,

  // ARDUINO
  input ARDUINO_RESET_N,
  input [15:0] ARDUINO_IO,

  // HDMI
  input [23:0] HDMI_TX_D,
  input HDMI_I2C_SCL,
  input HDMI_I2C_SDA,
  input HDMI_I2S,
  input HDMI_LRCLK,
  input HDMI_MCLK,
  input HDMI_SCLK,
  input HDMI_TX_CLK,
  input HDMI_TX_DE,
  input HDMI_TX_HS,
  input HDMI_TX_INT,
  input HDMI_TX_VS,

  // GPIO
  input [35:0] GPIO_0,
  output [35:0] GPIO_1,
  input [1:0] KEY,
  input [3:0] SW,
  output [7:0] LED,

  // virtual pins
  input [`WIDTH-1:0] in_data,
  input [`WIDTH-1:0] in_datb,
  output logic [`WIDTH-1:0] out_data = '0
);


// clocks ======================================================================

logic sys_pll_locked;  // asyn
logic clk125;
logic clk500;

logic nrst;

sys_pll sys_pll_b (
  .refclk( FPGA_CLK1_50 ),
  .rst( 1'b0 ),
  .outclk_0( clk125 ),
  .outclk_1( clk500 ),
  .locked( sys_pll_locked )
);

logic [31:0] div_clk125;
clk_divider #(
  .WIDTH( 32 )
) cd_125 (
  .clk( clk125 ),
  .nrst( nrst ),
  .ena( 1'b1 ),
  .out( div_clk125[31:0] )
);

logic [31:0] div_clk500;
clk_divider #(
  .WIDTH( 32 )
) cd_500 (
  .clk( clk500 ),
  .nrst( nrst ),
  .ena( 1'b1 ),
  .out( div_clk500[31:0] )
);

assign LED[7] = div_clk125[25];

// nrst ========================================================================
logic [3:0] sw_s;
logic [1:0] key_s;

always_ff @(posedge clk125) begin
  nrst <= ~key_s[0];  // external reset
end

assign LED[6] = ~nrst;

// buttons =====================================================================

delay #(
    .LENGTH( 2 ),
    .WIDTH( 6 )
) sw_SYNC_ATTR (
    .clk( clk125 ),
    .nrst( 1'b1 ),
    .ena( 1'b1 ),
    .in( {SW[3:0], KEY[1:0]} ),
    .out( {sw_s[3:0], key_s[1:0]} )
);

logic [3:0] sw_s_rise;
logic [1:0] key_s_rise;

edge_detect #(
  .WIDTH( 6 )
) sw_s_ed (
  .clk( clk125 ),
  .anrst( nrst ),
  .in( {sw_s[3:0], key_s[1:0]} ),
  .rising( {sw_s_rise[3:0], key_s_rise[1:0]} ),
  .falling(  ),
  .both(  )
);

// =============================================================================

// input registers
logic [`WIDTH-1:0] in_data_reg = 0;
always_ff @(posedge clk500) begin
  if( ~nrst ) begin
    in_data_reg[`WIDTH-1:0] <= '0;
  end else begin
    in_data_reg[`WIDTH-1:0] <= in_data[`WIDTH-1:0];
  end
end

// place your test logic here ==================================================

logic [`WIDTH-1:0] out_data_comb = 0;
always_comb begin
  out_data_comb[`WIDTH-1:0] <= in_data_reg[`WIDTH-1:0] ^ div_clk500[31:0];
end

// output registers
always_ff @(posedge clk500) begin
  if( ~nrst ) begin
    out_data[`WIDTH-1:0] <= '0;
  end else begin
    out_data[`WIDTH-1:0] <= out_data_comb[`WIDTH-1:0];
  end
end

// =============================================================================

/*logic [`WIDTH-1:0] in_datc;
logic [`WIDTH-1:0] in_datd;
logic [`WIDTH-1:0] out_datc;
assign out_datc[`WIDTH-1:0] = in_datc[`WIDTH-1:0] | in_datd[`WIDTH-1:0];

jtag_io jtag_io_b (
  .clk_clk( clk125 ),
  .reset_reset_n( nrst ),
  .out0_export( in_datc[`WIDTH-1:0] ),
  .out1_export( in_datd[`WIDTH-1:0] ),
  .in0_export( div_clk125[31:0] ),
  .in1_export( out_datc[`WIDTH-1:0] )
);
*/

`include "clogb2.svh"

